export interface UseAssetManagementResult {
  registerGenerationAsset: (data: ReturnType<typeof getGenerationDropData>) => string | null;
  uploadImageGeneration: (file: File) => Promise<{
    generationId: string;
    variantType: 'image';
    imageUrl: string;
    thumbUrl: string;
    metadata: {
      content_type: string;
      original_filename: string;
    };
