type DragMode =
  | 'move'
  | 'resize-nw'
  | 'resize-ne'
  | 'resize-sw'
  | 'resize-se'
  | 'crop-n'
  | 'crop-s'
  | 'crop-e'
  | 'crop-w';
type CropValues = { cropTop: number; cropBottom: number; cropLeft: number; cropRight: number };
