import { useCallback, useRef, useState } from 'react';
import type { PreviewHandle } from '@/tools/video-editor/components/PreviewPanel/RemotionPreview';
import { useTimelineSync } from '@/tools/video-editor/hooks/useTimelineSync';
import type { TimelineCanvasHandle } from '@/tools/video-editor/types/timeline-canvas';

export interface UseTimelinePlaybackResult {
  currentTime: number;
  setCurrentTime: React.Dispatch<React.SetStateAction<number>>;
  timelineRef: React.RefObject<TimelineCanvasHandle | null>;
  previewRef: React.RefObject<PreviewHandle | null>;
  playerContainerRef: React.RefObject<HTMLDivElement | null>;
  timelineWrapperRef: React.RefObject<HTMLDivElement | null>;
  onPreviewTimeUpdate: (time: number) => void;
  onCursorDrag: (time: number) => void;
  onClickTimeArea: (time: number) => undefined;
  formatTime: (time: number) => string;
}

export function useTimelinePlayback(): UseTimelinePlaybackResult {
  const timelineRef = useRef<TimelineCanvasHandle>(null);
  const previewRef = useRef<PreviewHandle>(null);
  const playerContainerRef = useRef<HTMLDivElement | null>(null);
  const timelineWrapperRef = useRef<HTMLDivElement | null>(null);
  const isSyncingFromPreview = useRef(false);
  const isSyncingFromTimeline = useRef(false);

  const [currentTime, setCurrentTime] = useState(0);

  const { onPreviewTimeUpdate, onCursorDrag, onClickTimeArea } = useTimelineSync({
    timelineRef,
    previewRef,
    setCurrentTime,
    isSyncingFromPreview,
    isSyncingFromTimeline,
  });

  const formatTime = useCallback((time: number) => {
    const mins = Math.floor(time / 60);
    const secs = Math.floor(time % 60);
    const ms = Math.floor((time % 1) * 100);
    return `${mins}:${secs.toString().padStart(2, '0')}.${ms.toString().padStart(2, '0')}`;
  }, []);

  return {
    currentTime,
    setCurrentTime,
    timelineRef,
    previewRef,
    playerContainerRef,
    timelineWrapperRef,
    onPreviewTimeUpdate,
    onCursorDrag,
    onClickTimeArea,
    formatTime,
  };
}

import type { TrackDefinition, TrackKind } from '@/tools/video-editor/types';
import type { ClipMeta, ClipOrderMap } from '@/tools/video-editor/lib/timeline-data';

export const ROW_HEIGHT = 36;
export const SCALE_SECONDS = 5;
export const TIMELINE_START_LEFT = 20;

export const isEditableTarget = (target: EventTarget | null): boolean => {
  if (!(target instanceof HTMLElement)) {
    return false;
  }

  return Boolean(target.closest("input, textarea, select, [contenteditable='true']"));
};

export const formatTime = (time: number): string => {
  const mins = Math.floor(time / 60);
  const secs = Math.floor(time % 60);
  const ms = Math.floor((time % 1) * 100);
  return `${mins}:${secs.toString().padStart(2, '0')}.${ms.toString().padStart(2, '0')}`;
};

export const updateClipOrder = (
  current: ClipOrderMap,
  trackId: string,
  update: (ids: string[]) => string[],
): ClipOrderMap => {
  return {
    ...current,
    [trackId]: update(current[trackId] ?? []),
  };
};

export const buildTrackClipOrder = (
  tracks: TrackDefinition[],
  clipOrder: ClipOrderMap,
  removedIds: string[] = [],
): ClipOrderMap => {
  return Object.fromEntries(
    tracks.map((track) => [
      track.id,
      (clipOrder[track.id] ?? []).filter((clipId) => !removedIds.includes(clipId)),
    ]),
  );
};

export const moveClipBetweenTracks = (
  clipOrder: ClipOrderMap,
  clipId: string,
  sourceTrackId: string,
  targetTrackId: string,
): ClipOrderMap => {
  if (sourceTrackId === targetTrackId) {
    return clipOrder;
  }

  return {
    ...clipOrder,
    [sourceTrackId]: (clipOrder[sourceTrackId] ?? []).filter((id) => id !== clipId),
    [targetTrackId]: [...(clipOrder[targetTrackId] ?? []).filter((id) => id !== clipId), clipId],
  };
};

export const getCompatibleTrackId = (
  tracks: TrackDefinition[],
  desiredTrackId: string | undefined,
  assetKind: TrackKind,
  selectedTrackId: string | null,
): string | null => {
  const compatibleTracks = tracks.filter((track) => track.kind === assetKind);
  if (compatibleTracks.length === 0) {
    return null;
  }

  if (desiredTrackId) {
    const exact = compatibleTracks.find((track) => track.id === desiredTrackId);
    return exact?.id ?? null;
  }

  if (selectedTrackId) {
    const selected = compatibleTracks.find((track) => track.id === selectedTrackId);
    if (selected) {
      return selected.id;
    }
  }

  return compatibleTracks[0].id;
};

export const buildRowTrackPatches = (
  rows: { id: string; actions: { id: string }[] }[],
): Record<string, Partial<ClipMeta>> => {
  const patches: Record<string, Partial<ClipMeta>> = {};
  for (const row of rows) {
    for (const action of row.actions) {
      patches[action.id] = { track: row.id };
    }
  }

  return patches;
};

export const rawRowIndexFromY = (
  clientY: number,
  containerTop: number,
  scrollTop: number,
  rowHeight: number,
): number => {
  const relativeY = clientY - containerTop + scrollTop;
  return Math.floor(Math.max(0, relativeY) / rowHeight);
};

export interface DropTargetResult {
  kind: 'track' | 'create' | 'reject';
  trackId?: string;
}

export const resolveDropTarget = (
  tracks: TrackDefinition[],
  rowIndex: number,
  rowCount: number,
  sourceKind: TrackKind,
): DropTargetResult => {
  if (rowIndex >= rowCount) {
    return { kind: 'create' };
  }
  const targetTrack = tracks[rowIndex];
  if (!targetTrack || targetTrack.kind !== sourceKind) {
    return { kind: 'reject' };
  }
  return { kind: 'track', trackId: targetTrack.id };
};

