import { useCallback, useRef } from 'react';
import type { PreviewHandle } from '@/tools/video-editor/components/PreviewPanel/RemotionPreview';
import type { TimelineCanvasHandle } from '@/tools/video-editor/types/timeline-canvas';

interface UseTimelineSyncOptions {
  timelineRef: React.RefObject<TimelineCanvasHandle | null>;
  previewRef: React.RefObject<PreviewHandle | null>;
  setCurrentTime: React.Dispatch<React.SetStateAction<number>>;
  isSyncingFromPreview: React.MutableRefObject<boolean>;
  isSyncingFromTimeline: React.MutableRefObject<boolean>;
}

export function useTimelineSync({
  timelineRef,
  previewRef,
  setCurrentTime,
  isSyncingFromPreview,
  isSyncingFromTimeline,
}: UseTimelineSyncOptions) {
  const lastTimeUpdateRef = useRef(0);

  const onPreviewTimeUpdate = useCallback((time: number) => {
    if (isSyncingFromTimeline.current) {
      return;
    }

    timelineRef.current?.setTime(time);

    const now = performance.now();
    if (now - lastTimeUpdateRef.current > 250) {
      lastTimeUpdateRef.current = now;
      isSyncingFromPreview.current = true;
      setCurrentTime(time);
      requestAnimationFrame(() => {
        isSyncingFromPreview.current = false;
      });
    }
  }, [isSyncingFromPreview, isSyncingFromTimeline, setCurrentTime, timelineRef]);

  const onCursorDrag = useCallback((time: number) => {
    if (isSyncingFromPreview.current) {
      return;
    }

    isSyncingFromTimeline.current = true;
    previewRef.current?.seek(time);
    setCurrentTime(time);
    requestAnimationFrame(() => {
      isSyncingFromTimeline.current = false;
    });
  }, [isSyncingFromPreview, isSyncingFromTimeline, previewRef, setCurrentTime]);

  const onClickTimeArea = useCallback((time: number) => {
    previewRef.current?.seek(time);
    setCurrentTime(time);
    return undefined;
  }, [previewRef, setCurrentTime]);

  return { onPreviewTimeUpdate, onCursorDrag, onClickTimeArea };
}

import { memo, useCallback, useLayoutEffect, useMemo } from 'react';
import { Timeline } from '@xzdarcy/react-timeline-editor';
import '@xzdarcy/react-timeline-editor/dist/react-timeline-editor.css';
import '@/tools/video-editor/components/TimelineEditor/timeline-overrides.css';
import { ClipAction } from '@/tools/video-editor/components/TimelineEditor/ClipAction';
import { DropIndicator } from '@/tools/video-editor/components/TimelineEditor/DropIndicator';
import { TrackLabel } from '@/tools/video-editor/components/TimelineEditor/TrackLabel';
import { ROW_HEIGHT, TIMELINE_START_LEFT } from '@/tools/video-editor/lib/coordinate-utils';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';
import { useClipDrag } from '@/tools/video-editor/hooks/useClipDrag';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

function TimelineEditorComponent() {
  const {
    data,
    resolvedConfig,
    timelineRef,
    timelineWrapperRef,
    dataRef,
    moveClipToRow,
    createTrackAndMoveClip,
    setSelectedClipId,
    setSelectedTrackId,
    scale,
    scaleWidth,
    coordinator,
    indicatorRef,
    editAreaRef,
    selectedClipId,
    selectedTrackId,
    handleTrackPopoverChange,
    handleReorderTrack,
    handleRemoveTrack,
    handleSplitClipAtTime,
    handleDeleteClip,
    onChange,
    onCursorDrag,
    onClickTimeArea,
    onActionResizeStart,
    onActionResizeEnd,
    onTimelineDragOver,
    onTimelineDragLeave,
    onTimelineDrop,
    onDoubleClickAsset,
  } = useTimelineEditorContext();

  // useClipDrag handles all internal clip drag interactions (horizontal moves,
  // cross-track moves, and new-track creation) using the same fixed-position
  // drop indicators as external HTML5 drag-drop.
  useClipDrag({
    timelineWrapperRef,
    dataRef,
    moveClipToRow,
    createTrackAndMoveClip,
    setSelectedClipId,
    setSelectedTrackId,
    coordinator,
    rowHeight: ROW_HEIGHT,
    scale,
    scaleWidth,
    startLeft: TIMELINE_START_LEFT,
  });

  useLayoutEffect(() => {
    const wrapper = timelineWrapperRef.current;
    const nextEditArea = wrapper?.querySelector<HTMLElement>('.timeline-editor-edit-area') ?? null;
    editAreaRef.current = nextEditArea;

    return () => {
      if (editAreaRef.current === nextEditArea) {
        editAreaRef.current = null;
      }
    };
  }, [data, editAreaRef, timelineWrapperRef]);

  const scaleCount = useMemo(() => {
    if (!data) {
      return 1;
    }

    let maxEnd = 0;
    for (const row of data.rows) {
      for (const action of row.actions) {
        maxEnd = Math.max(maxEnd, action.end);
      }
    }

    return Math.ceil((maxEnd + 20) / scale) + 1;
  }, [data, scale]);

  const thumbnailMap = useMemo<Record<string, string>>(() => {
    if (!resolvedConfig) {
      return {};
    }

    return resolvedConfig.clips.reduce<Record<string, string>>((acc, clip) => {
      if (clip.clipType === 'text' || !clip.assetEntry?.type?.startsWith('image')) {
        return acc;
      }

      acc[clip.id] = clip.assetEntry.src;
      return acc;
    }, {});
  }, [resolvedConfig]);

  const handleClipSelect = useCallback((clipId: string, trackId: string) => {
    setSelectedClipId(clipId);
    setSelectedTrackId(trackId);
  }, [setSelectedClipId, setSelectedTrackId]);

  const pixelsPerSecond = scaleWidth / scale;

  const clientXToTime = useCallback((clientX: number): number => {
    const wrapper = timelineWrapperRef.current;
    if (!wrapper) return 0;
    const editArea = wrapper.querySelector<HTMLElement>('.timeline-editor-edit-area');
    const grid = editArea?.querySelector<HTMLElement>('.ReactVirtualized__Grid')
      ?? wrapper.querySelector<HTMLElement>('.ReactVirtualized__Grid');
    const rect = (editArea ?? wrapper).getBoundingClientRect();
    const scrollLeft = grid?.scrollLeft ?? 0;
    return Math.max(0, (clientX - rect.left + scrollLeft - TIMELINE_START_LEFT) / pixelsPerSecond);
  }, [pixelsPerSecond, timelineWrapperRef]);

  const handleSplitClipHere = useCallback((clipId: string, clientX: number) => {
    const time = clientXToTime(clientX);
    handleSplitClipAtTime(clipId, time);
  }, [clientXToTime, handleSplitClipAtTime]);

  const getActionRender = useCallback((action: TimelineAction) => {
    const clipMeta = data?.meta[action.id];
    if (!clipMeta) {
      return null;
    }

    const clipWidthPx = (action.end - action.start) * pixelsPerSecond;
    const thumbnailSrc = clipWidthPx >= 40 ? thumbnailMap[action.id] : undefined;

    return (
      <ClipAction
        action={action}
        clipMeta={clipMeta}
        isSelected={selectedClipId === action.id}
        thumbnailSrc={thumbnailSrc}
        onSelect={handleClipSelect}
        onDoubleClickAsset={onDoubleClickAsset}
        onSplitHere={handleSplitClipHere}
        onDeleteClip={handleDeleteClip}
      />
    );
  }, [data, handleClipSelect, handleDeleteClip, handleSplitClipHere, onDoubleClickAsset, pixelsPerSecond, selectedClipId, thumbnailMap]);

  const kindCountMap = useMemo(() => {
    if (!data) {
      return {} as Record<string, number>;
    }

    return data.tracks.reduce<Record<string, number>>((counts, track) => {
      counts[track.kind] = (counts[track.kind] ?? 0) + 1;
      return counts;
    }, {});
  }, [data]);

  const immovableRows = useMemo(() => {
    return data?.rows.map((row) => ({
      ...row,
      actions: row.actions.map((action) => ({
        ...action,
        movable: false,
      })),
    })) ?? [];
  }, [data?.rows]);

  if (!data) {
    return null;
  }

  return (
    <div className="flex h-full overflow-hidden rounded-xl border border-border bg-card/80">
      <div className="flex w-36 shrink-0 flex-col overflow-y-auto border-r border-border pt-[30px]">
        {data.tracks.map((track, index) => (
          <TrackLabel
            key={track.id}
            track={track}
            isSelected={selectedTrackId === track.id}
            trackCount={data.tracks.length}
            trackIndex={index}
            sameKindCount={kindCountMap[track.kind] ?? 0}
            onSelect={setSelectedTrackId}
            onChange={handleTrackPopoverChange}
            onReorder={handleReorderTrack}
            onRemove={handleRemoveTrack}
          />
        ))}
      </div>
      <div
        ref={timelineWrapperRef}
        className="timeline-wrapper relative min-w-0 flex-1 overflow-hidden"
        onDragOver={onTimelineDragOver}
        onDragLeave={onTimelineDragLeave}
        onDrop={onTimelineDrop}
      >
        <Timeline
          ref={timelineRef}
          style={{ width: '100%', height: '100%' }}
          editorData={immovableRows}
          effects={data.effects}
          onChange={onChange}
          scale={scale}
          scaleWidth={scaleWidth}
          minScaleCount={scaleCount}
          maxScaleCount={scaleCount}
          scaleSplitCount={5}
          startLeft={TIMELINE_START_LEFT}
          rowHeight={ROW_HEIGHT}
          autoScroll
          dragLine
          getActionRender={getActionRender}
          onCursorDrag={onCursorDrag}
          onClickTimeArea={onClickTimeArea}
          onActionResizeStart={onActionResizeStart}
          onActionResizeEnd={onActionResizeEnd}
        />
        <DropIndicator ref={indicatorRef} editAreaRef={editAreaRef} />
      </div>
    </div>
  );
}

export const TimelineEditor = memo(TimelineEditorComponent);

import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
  type ReactNode,
  type RefObject,
  type UIEvent,
} from 'react';
import { TimeRuler } from '@/tools/video-editor/components/TimelineEditor/TimeRuler';
import type { TimelineAction, TimelineCanvasHandle, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';

interface ScrollMetrics {
  scrollLeft: number;
  scrollTop: number;
}

export interface TimelineCanvasProps {
  rows: TimelineRow[];
  scale: number;
  scaleWidth: number;
  scaleSplitCount: number;
  startLeft: number;
  rowHeight: number;
  minScaleCount: number;
  maxScaleCount: number;
  getActionRender?: (action: TimelineAction, row: TimelineRow) => ReactNode;
  onCursorDrag: (time: number) => void;
  onClickTimeArea: (time: number) => void;
  onScroll?: (metrics: ScrollMetrics) => void;
  trackLabelRef?: RefObject<HTMLElement | null>;
}

const ACTION_VERTICAL_MARGIN = 4;
const CURSOR_WIDTH = 2;

const clamp = (value: number, min: number, max: number): number => Math.min(max, Math.max(min, value));

const buildGridBackground = (startLeft: number, scaleWidth: number, scaleSplitCount: number, rowHeight: number): string => {
  const splitWidth = scaleWidth / Math.max(scaleSplitCount, 1);
  return [
    `linear-gradient(to right, rgb(9 9 11) 0, rgb(9 9 11) ${startLeft}px, transparent ${startLeft}px)`,
    `repeating-linear-gradient(to right, rgb(63 63 70 / 0.55) 0, rgb(63 63 70 / 0.55) 1px, transparent 1px, transparent ${scaleWidth}px)`,
    `repeating-linear-gradient(to right, rgb(39 39 42 / 0.32) 0, rgb(39 39 42 / 0.32) 1px, transparent 1px, transparent ${splitWidth}px)`,
    `repeating-linear-gradient(to bottom, rgb(63 63 70 / 0.6) 0, rgb(63 63 70 / 0.6) 1px, transparent 1px, transparent ${rowHeight}px)`,
  ].join(',');
};

export const TimelineCanvas = forwardRef<TimelineCanvasHandle, TimelineCanvasProps>(function TimelineCanvas({
  rows,
  scale,
  scaleWidth,
  scaleSplitCount,
  startLeft,
  rowHeight,
  minScaleCount,
  maxScaleCount,
  getActionRender,
  onCursorDrag,
  onClickTimeArea,
  onScroll,
  trackLabelRef,
}: TimelineCanvasProps, ref) {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const cursorRef = useRef<HTMLDivElement>(null);
  const timeRef = useRef(0);
  const playRateRef = useRef(1);
  const scrollMetricsRef = useRef<ScrollMetrics>({ scrollLeft: 0, scrollTop: 0 });
  const [scrollLeft, setScrollLeft] = useState(0);

  const pixelsPerSecond = scaleWidth / Math.max(scale, Number.EPSILON);
  const maxEnd = useMemo(() => rows.reduce(
    (currentMax, row) => row.actions.reduce(
      (rowMax, action) => Math.max(rowMax, action.end),
      currentMax,
    ),
    0,
  ), [rows]);
  const derivedScaleCount = Math.ceil(maxEnd / Math.max(scale, Number.EPSILON)) + 1;
  const scaleCount = clamp(derivedScaleCount, minScaleCount, maxScaleCount);
  const totalWidth = startLeft + scaleCount * scaleWidth;
  const totalHeight = Math.max(rows.length * rowHeight, rowHeight);

  const syncCursor = useCallback((time = timeRef.current) => {
    const cursor = cursorRef.current;
    if (!cursor) {
      return;
    }

    const left = startLeft + time * pixelsPerSecond - scrollMetricsRef.current.scrollLeft;
    cursor.style.transform = `translateX(${left}px)`;
  }, [pixelsPerSecond, startLeft]);

  const handleSetTime = useCallback((time: number) => {
    timeRef.current = Math.max(0, time);
    syncCursor(timeRef.current);
  }, [syncCursor]);

  useEffect(() => {
    syncCursor();
  }, [syncCursor]);

  useImperativeHandle(ref, () => ({
    get target() {
      return scrollContainerRef.current;
    },
    listener: null,
    isPlaying: false,
    isPaused: true,
    setTime: handleSetTime,
    getTime: () => timeRef.current,
    setPlayRate: (rate: number) => {
      playRateRef.current = rate;
    },
    getPlayRate: () => playRateRef.current,
    reRender: () => syncCursor(),
    play: ({ toTime }) => {
      if (typeof toTime === 'number') {
        handleSetTime(toTime);
      }
      return false;
    },
    pause: () => {},
    setScrollLeft: (value: number) => {
      if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollLeft = Math.max(0, value);
      }
    },
    setScrollTop: (value: number) => {
      if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTop = Math.max(0, value);
      }
    },
  }), [handleSetTime, syncCursor]);

  const handleScroll = (event: UIEvent<HTMLDivElement>) => {
    const target = event.currentTarget;
    const nextMetrics = {
      scrollLeft: target.scrollLeft,
      scrollTop: target.scrollTop,
    };

    scrollMetricsRef.current = nextMetrics;
    if (trackLabelRef?.current && trackLabelRef.current.scrollTop !== nextMetrics.scrollTop) {
      trackLabelRef.current.scrollTop = nextMetrics.scrollTop;
    }
    if (nextMetrics.scrollLeft !== scrollLeft) {
      setScrollLeft(nextMetrics.scrollLeft);
    }
    syncCursor();
    onScroll?.(nextMetrics);
  };

  return (
    <div className="flex h-full min-h-0 flex-col bg-zinc-950/70">
      <TimeRuler
        scale={scale}
        scaleWidth={scaleWidth}
        scaleSplitCount={scaleSplitCount}
        startLeft={startLeft}
        scrollLeft={scrollLeft}
        totalWidth={totalWidth}
        onClickTimeArea={onClickTimeArea}
        onCursorDrag={onCursorDrag}
      />
      <div
        ref={scrollContainerRef}
        className="timeline-canvas-edit-area relative min-h-0 flex-1 overflow-auto overscroll-contain"
        onScroll={handleScroll}
      >
        <div
          className="relative"
          style={{
            width: totalWidth,
            height: totalHeight,
            minHeight: '100%',
            backgroundImage: buildGridBackground(startLeft, scaleWidth, scaleSplitCount, rowHeight),
            backgroundPosition: `${startLeft}px 0, ${startLeft}px 0, ${startLeft}px 0, 0 0`,
          }}
        >
          {rows.map((row, rowIndex) => {
            const top = rowIndex * rowHeight;
            const actionHeight = Math.max(12, rowHeight - ACTION_VERTICAL_MARGIN * 2);

            return (
              <div
                key={row.id}
                className="absolute left-0 right-0"
                data-row-id={row.id}
                style={{ top, height: rowHeight }}
              >
                {row.actions.map((action) => {
                  const left = startLeft + action.start * pixelsPerSecond;
