import { useCallback, useRef } from 'react';
import { buildRowTrackPatches } from '@/tools/video-editor/lib/coordinate-utils';
import { getSourceTime, type ClipMeta, type TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';
import type { TimelineAction, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';

export interface UseClipResizeArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  applyTimelineEdit: UseTimelineDataResult['applyTimelineEdit'];
}

export interface UseClipResizeResult {
  onActionResizeStart: ({ action }: { action: TimelineAction }) => void;
  onActionResizeEnd: ({ action, row }: { action: TimelineAction; row: TimelineRow; dir: string }) => void;
}

export function useClipResize({
  dataRef,
  applyTimelineEdit,
}: UseClipResizeArgs): UseClipResizeResult {
  const resizeStartRef = useRef<Record<string, { start: number; from: number }>>({});

  const onActionResizeStart = useCallback(({ action }: { action: TimelineAction }) => {
    if (action.id.startsWith('uploading-')) return;
    const clipMeta = dataRef.current?.meta[action.id];
    if (!clipMeta || typeof clipMeta.hold === 'number') {
      return;
    }

    resizeStartRef.current[action.id] = {
      start: action.start,
      from: clipMeta.from ?? 0,
    };
  }, [dataRef]);

  const onActionResizeEnd = useCallback(({ action, row }: { action: TimelineAction; row: TimelineRow; dir: string }) => {
    if (action.id.startsWith('uploading-')) return;
    const current = dataRef.current;
    const clipMeta = current?.meta[action.id];
    if (!current || !clipMeta) {
      return;
    }

    const metaUpdates: Record<string, Partial<ClipMeta>> = {
      ...buildRowTrackPatches(current.rows),
      [action.id]: {
        track: row.id,
      },
    };

    if (typeof clipMeta.hold !== 'number') {
      const origin = resizeStartRef.current[action.id];
      if (origin && action.start !== origin.start) {
        metaUpdates[action.id] = {
          ...metaUpdates[action.id],
          from: Math.max(0, origin.from + (action.start - origin.start) * (clipMeta.speed ?? 1)),
        };
      }

      metaUpdates[action.id] = {
        ...metaUpdates[action.id],
        to: getSourceTime(
          {
            from: clipMeta.from ?? 0,
            start: action.start,
            speed: clipMeta.speed ?? 1,
          },
          action.end,
        ),
      };
    }

    const nextRows = current.rows.map((entry) => {
      if (entry.id !== row.id) {
        return entry;
      }

      return {
        ...entry,
        actions: entry.actions.map((candidate) => {
          return candidate.id === action.id
            ? { ...candidate, start: action.start, end: action.end }
            : candidate;
        }),
      };
    });

    applyTimelineEdit(nextRows, metaUpdates);
    delete resizeStartRef.current[action.id];
  }, [applyTimelineEdit, dataRef]);

  return {
    onActionResizeStart,
    onActionResizeEnd,
  };
}

import { useEffect, useRef } from 'react';
import type { Dispatch, MutableRefObject, RefObject, SetStateAction } from 'react';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type { TrackKind } from '@/tools/video-editor/types';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';

const DRAG_THRESHOLD_PX = 4;

export interface ActionDragState {
  rowId: string;
  initialStart: number;
  initialEnd: number;
  latestStart: number;
  latestEnd: number;
}

interface UseCrossTrackDragOptions {
  timelineWrapperRef: RefObject<HTMLDivElement | null>;
  dataRef: MutableRefObject<TimelineData | null>;
  moveClipToRow: (clipId: string, targetRowId: string, newStartTime?: number) => void;
  createTrackAndMoveClip: (clipId: string, kind: TrackKind, newStartTime?: number) => void;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  coordinator: DragCoordinator;
  rowHeight: number;
  scale: number;
  scaleWidth: number;
  startLeft: number;
}

interface DragSession {
  pointerId: number;
  clipId: string;
  sourceRowId: string;
  sourceKind: TrackKind;
  startClientX: number;
  startClientY: number;
  pointerOffsetX: number;
  pointerOffsetY: number;
  latestStart: number;
  clipDuration: number;
  clipEl: HTMLElement;
  moveListener: (event: PointerEvent) => void;
  upListener: (event: PointerEvent) => void;
  cancelListener: (event: PointerEvent) => void;
  /** Floating clone shown during cross-track drag. */
  floatingGhostEl: HTMLElement | null;
  hasMoved: boolean;
}

export const useClipDrag = ({
  timelineWrapperRef,
  dataRef,
  moveClipToRow,
  createTrackAndMoveClip,
  setSelectedClipId,
  setSelectedTrackId,
  coordinator,
  rowHeight,
  scale,
  scaleWidth,
  startLeft,
}: UseCrossTrackDragOptions): void => {
  const dragSessionRef = useRef<DragSession | null>(null);
  const actionDragStateRef = useRef<ActionDragState | null>(null);
  const crossTrackActiveRef = useRef(false);

  useEffect(() => {
    const wrapper = timelineWrapperRef.current;
    if (!wrapper) {
      return undefined;
    }

    const clearSession = (session: DragSession | null, deferDeactivate = false) => {
      coordinator.end();
      if (!session) {
        actionDragStateRef.current = null;
        if (!deferDeactivate) {
          crossTrackActiveRef.current = false;
        }
        return;
      }

      session.floatingGhostEl?.remove();
      window.removeEventListener('pointermove', session.moveListener);
      window.removeEventListener('pointerup', session.upListener);
      window.removeEventListener('pointercancel', session.cancelListener);
      try {
        if (session.clipEl.hasPointerCapture(session.pointerId)) {
          session.clipEl.releasePointerCapture(session.pointerId);
        }
      } catch {
        // Pointer capture can already be released by the browser during teardown.
      }

      dragSessionRef.current = null;
      actionDragStateRef.current = null;
      if (deferDeactivate) {
        window.requestAnimationFrame(() => {
          if (!dragSessionRef.current) {
            crossTrackActiveRef.current = false;
          }
        });
      } else {
        crossTrackActiveRef.current = false;
      }
    };

    // ── Helpers ──────────────────────────────────────────────────────

    const updateFloatingGhostPosition = (session: DragSession, event: PointerEvent) => {
      if (!session.floatingGhostEl) return;
      session.floatingGhostEl.style.left = `${event.clientX - session.pointerOffsetX}px`;
      session.floatingGhostEl.style.top = `${event.clientY - session.pointerOffsetY}px`;
    };

    const createFloatingGhost = (clipEl: HTMLElement): HTMLElement => {
      const rect = clipEl.getBoundingClientRect();
      const el = clipEl.cloneNode(true) as HTMLElement;
      el.classList.add('cross-track-ghost');
      el.style.width = `${rect.width}px`;
      el.style.height = `${rect.height}px`;
      document.body.appendChild(el);
      return el;
    };

    // ── Pointer handlers ─────────────────────────────────────────────

    const handlePointerDown = (event: PointerEvent) => {
      if (event.button !== 0) return;

      const clipTarget = event.target instanceof HTMLElement ? event.target.closest<HTMLElement>('.clip-action') : null;
      if (!clipTarget || (event.target instanceof HTMLElement && event.target.closest("[data-delete-clip='true']"))) return;

      const clipId = clipTarget.dataset.clipId;
      const rowId = clipTarget.dataset.rowId;
      if (!clipId || !rowId) return;

      const current = dataRef.current;
      const sourceTrack = current?.tracks.find((track) => track.id === rowId);
      const sourceRow = current?.rows.find((row) => row.id === rowId);
      const sourceAction = sourceRow?.actions.find((action) => action.id === clipId);
      if (!current || !sourceTrack || !sourceAction) return;

      clearSession(dragSessionRef.current);

      const clipRect = clipTarget.getBoundingClientRect();
      const initialStart = sourceAction.start;
      const clipDuration = sourceAction.end - sourceAction.start;
      actionDragStateRef.current = {
        rowId,
        initialStart,
        initialEnd: sourceAction.end,
        latestStart: initialStart,
        latestEnd: sourceAction.end,
      };

      const handlePointerMove = (moveEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || moveEvent.pointerId !== session.pointerId) return;

        const dx = moveEvent.clientX - session.startClientX;
        const dy = moveEvent.clientY - session.startClientY;
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Don't show anything until the pointer actually moves (avoids flash on click)
        if (!session.hasMoved && distance < DRAG_THRESHOLD_PX) return;

        // First move past threshold — capture the pointer so we own all subsequent events
        // and the timeline library can't start its own competing drag.
        if (!session.hasMoved) {
          session.hasMoved = true;
          try { session.clipEl.setPointerCapture(session.pointerId); } catch { /* ok */ }
        }

        // Prevent default on all moves once dragging to stop the library's handler
        moveEvent.preventDefault();

        const nextPosition = coordinator.update({
          clientX: moveEvent.clientX,
          clientY: moveEvent.clientY,
          sourceKind: session.sourceKind,
          clipDuration: session.clipDuration,
          clipOffsetX: session.pointerOffsetX,
        });

        session.latestStart = nextPosition.time;
        const dragState = actionDragStateRef.current;
        if (dragState) {
          const dur = dragState.initialEnd - dragState.initialStart;
          dragState.latestStart = nextPosition.time;
          dragState.latestEnd = nextPosition.time + dur;
        }

        // Activate cross-track mode (floating ghost) on vertical threshold
        if (!crossTrackActiveRef.current && Math.abs(dy) >= 10) {
          crossTrackActiveRef.current = true;
          session.floatingGhostEl = createFloatingGhost(session.clipEl);
          updateFloatingGhostPosition(session, moveEvent);
        }

        if (crossTrackActiveRef.current) {
          updateFloatingGhostPosition(session, moveEvent);
        }

        if (session.floatingGhostEl) {
          session.floatingGhostEl.style.cursor = nextPosition.isReject ? 'not-allowed' : '';
        }
      };

      const handlePointerUp = (upEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || upEvent.pointerId !== session.pointerId) return;

        const dropPosition = coordinator.lastPosition;
        const nextStart = dropPosition?.time ?? actionDragStateRef.current?.latestStart ?? session.latestStart;
        if (crossTrackActiveRef.current) {
          upEvent.preventDefault();
          if (dropPosition?.isNewTrack) {
            createTrackAndMoveClip(session.clipId, session.sourceKind, nextStart);
          } else if (dropPosition?.trackId && !dropPosition.isReject) {
            moveClipToRow(session.clipId, dropPosition.trackId, nextStart);
            setSelectedTrackId(dropPosition.trackId);
          } else {
            moveClipToRow(session.clipId, session.sourceRowId, nextStart);
            setSelectedTrackId(session.sourceRowId);
          }
          setSelectedClipId(session.clipId);
          clearSession(session, true);
          return;
        }

        // Same-row move — apply the horizontal position change
        if (session.hasMoved) {
          moveClipToRow(session.clipId, session.sourceRowId, nextStart);
        }
        setSelectedClipId(session.clipId);
        setSelectedTrackId(session.sourceRowId);
        clearSession(session);
      };

      const handlePointerCancel = (cancelEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || cancelEvent.pointerId !== session.pointerId) return;
        clearSession(session);
      };

      dragSessionRef.current = {
        pointerId: event.pointerId,
        clipId,
        sourceRowId: rowId,
        sourceKind: sourceTrack.kind,
        startClientX: event.clientX,
        startClientY: event.clientY,
        pointerOffsetX: event.clientX - clipRect.left,
        pointerOffsetY: event.clientY - clipRect.top,
        latestStart: initialStart,
        clipDuration,
        clipEl: clipTarget,
        moveListener: handlePointerMove,
        upListener: handlePointerUp,
        cancelListener: handlePointerCancel,
        floatingGhostEl: null,
        hasMoved: false,
      };

      window.addEventListener('pointermove', handlePointerMove);
      window.addEventListener('pointerup', handlePointerUp);
      window.addEventListener('pointercancel', handlePointerCancel);
    };

    const handleBlur = () => {
      clearSession(dragSessionRef.current);
    };

    // Use capture phase so this fires BEFORE ClipAction's stopPropagation
    wrapper.addEventListener('pointerdown', handlePointerDown, true);
    window.addEventListener('blur', handleBlur);
    return () => {
      wrapper.removeEventListener('pointerdown', handlePointerDown, true);
      window.removeEventListener('blur', handleBlur);
      clearSession(dragSessionRef.current);
    };
  }, [
    coordinator,
    createTrackAndMoveClip,
    dataRef,
    moveClipToRow,
    rowHeight,
    scale,
    scaleWidth,
    setSelectedClipId,
    setSelectedTrackId,
    startLeft,
    timelineWrapperRef,
  ]);
};

import { useCallback, useEffect, useMemo, useRef } from 'react';
import type { MutableRefObject } from 'react';
import type {
  DropIndicatorHandle,
  DropIndicatorPosition,
} from '@/tools/video-editor/components/TimelineEditor/DropIndicator';
import {
  computeDropPosition,
  type DropPosition,
} from '@/tools/video-editor/lib/drop-position';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TrackKind } from '@/tools/video-editor/types';

export interface DragCoordinator {
  update(params: {
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
    clipDuration?: number;
    clipOffsetX?: number;
  }): DropPosition;
  end(): void;
  lastPosition: DropPosition | null;
}

interface UseDragCoordinatorArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  scale: number;
  scaleWidth: number;
  startLeft: number;
  rowHeight: number;
}

interface UseDragCoordinatorResult {
  coordinator: DragCoordinator;
  indicatorRef: MutableRefObject<DropIndicatorHandle | null>;
  editAreaRef: MutableRefObject<HTMLElement | null>;
}

const buildFallbackPosition = (rowHeight: number, sourceKind: TrackKind | null): DropPosition => ({
  time: 0,
  rowIndex: 0,
  trackId: undefined,
  trackKind: sourceKind,
  trackName: '',
  isNewTrack: false,
  isReject: false,
  screenCoords: {
    rowTop: 0,
    rowLeft: 0,
    rowWidth: 0,
    rowHeight,
    clipLeft: 0,
    clipWidth: 0,
    ghostCenter: 0,
  },
});

const toIndicatorPosition = (position: DropPosition): DropIndicatorPosition => {
  const timeLabel = `${position.time.toFixed(1)}s`;
  return {
    rowTop: position.screenCoords.rowTop,
    rowHeight: position.screenCoords.rowHeight,
    rowLeft: position.screenCoords.rowLeft,
    rowWidth: position.screenCoords.rowWidth,
    lineLeft: position.screenCoords.ghostCenter,
    ghostLeft: position.screenCoords.clipLeft,
    ghostTop: position.screenCoords.rowTop + 2,
    ghostWidth: position.screenCoords.clipWidth,
    ghostHeight: Math.max(0, position.screenCoords.rowHeight - 4),
    ghostLabel: timeLabel,
    label: position.trackName ? `${position.trackName} · ${timeLabel}` : timeLabel,
    isNewTrack: position.isNewTrack,
    reject: position.isReject,
  };
};

export function useDragCoordinator({
  dataRef,
  scale,
  scaleWidth,
  startLeft,
  rowHeight,
}: UseDragCoordinatorArgs): UseDragCoordinatorResult {
  const indicatorRef = useRef<DropIndicatorHandle | null>(null);
  const editAreaRef = useRef<HTMLElement | null>(null);
  const lastPositionRef = useRef<DropPosition | null>(null);
  const pendingIndicatorRef = useRef<DropIndicatorPosition | null>(null);
  const frameRef = useRef<number | null>(null);

  const flushIndicator = useCallback(() => {
    frameRef.current = null;
    const pending = pendingIndicatorRef.current;
    if (!pending) {
      return;
    }

    indicatorRef.current?.show(pending);
  }, []);

  const end = useCallback(() => {
    if (frameRef.current !== null) {
      window.cancelAnimationFrame(frameRef.current);
      frameRef.current = null;
    }

    pendingIndicatorRef.current = null;
    lastPositionRef.current = null;
    indicatorRef.current?.hide();
  }, []);

  const update = useCallback((params: {
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
    clipDuration?: number;
    clipOffsetX?: number;
  }): DropPosition => {
    const wrapper = editAreaRef.current?.closest<HTMLDivElement>('.timeline-wrapper');
    if (!wrapper) {
      const fallback = lastPositionRef.current ?? buildFallbackPosition(rowHeight, params.sourceKind);
      lastPositionRef.current = fallback;
      return fallback;
    }

    const nextPosition = computeDropPosition({
      clientX: params.clientX,
      clientY: params.clientY,
      wrapper,
      dataRef,
      scale,
      scaleWidth,
      startLeft,
      rowHeight,
      sourceKind: params.sourceKind,
      clipDuration: params.clipDuration,
      clipOffsetX: params.clipOffsetX,
    });

    lastPositionRef.current = nextPosition;
    pendingIndicatorRef.current = toIndicatorPosition(nextPosition);

    if (frameRef.current === null) {
      frameRef.current = window.requestAnimationFrame(flushIndicator);
    }

    return nextPosition;
  }, [dataRef, flushIndicator, rowHeight, scale, scaleWidth, startLeft]);

  useEffect(() => {
    return () => {
      end();
    };
  }, [end]);

  const coordinator = useMemo<DragCoordinator>(() => ({
    update,
    end,
    get lastPosition() {
      return lastPositionRef.current;
    },
  }), [end, update]);

  return {
    coordinator,
    indicatorRef,
    editAreaRef,
  };
}

import type { DragEvent as ReactDragEvent, MutableRefObject } from 'react';
import { getDragType } from '@/shared/lib/dnd/dragDrop';
import { rawRowIndexFromY } from '@/tools/video-editor/lib/coordinate-utils';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TrackKind } from '@/tools/video-editor/types';

interface TimelineDomNodes {
  wrapper: HTMLDivElement;
  editArea: HTMLElement | null;
  grid: HTMLElement | null;
}

interface DropScreenCoords {
  rowTop: number;
  rowLeft: number;
  rowWidth: number;
  rowHeight: number;
  clipLeft: number;
  clipWidth: number;
  ghostCenter: number;
}

export interface DropPosition {
  time: number;
  rowIndex: number;
  trackId: string | undefined;
  trackKind: TrackKind | null;
  trackName: string;
  isNewTrack: boolean;
  isReject: boolean;
  screenCoords: DropScreenCoords;
}

export interface ComputeDropPositionParams {
  clientX: number;
  clientY: number;
  wrapper: HTMLDivElement;
  dataRef: MutableRefObject<TimelineData | null>;
  scale: number;
  scaleWidth: number;
  startLeft: number;
  rowHeight: number;
  sourceKind?: TrackKind | null;
  clipDuration?: number;
  clipOffsetX?: number;
}

const timelineDomNodeCache = new WeakMap<HTMLDivElement, Omit<TimelineDomNodes, 'wrapper'>>();

export const getTimelineDomNodes = (wrapper: HTMLDivElement): TimelineDomNodes => {
  const cached = timelineDomNodeCache.get(wrapper);
  if (
    cached
    && (cached.editArea === null || cached.editArea.isConnected)
    && (cached.grid === null || cached.grid.isConnected)
  ) {
    return { wrapper, ...cached };
  }

  const editArea = wrapper.querySelector<HTMLElement>('.timeline-editor-edit-area');
  const grid = editArea?.querySelector<HTMLElement>('.ReactVirtualized__Grid')
    ?? wrapper.querySelector<HTMLElement>('.ReactVirtualized__Grid');
  const nextNodes = { editArea, grid };
  timelineDomNodeCache.set(wrapper, nextNodes);
  return { wrapper, ...nextNodes };
};

export const computeDropPosition = ({
  clientX,
  clientY,
  wrapper,
  dataRef,
  scale,
  scaleWidth,
  startLeft,
  rowHeight,
  sourceKind = null,
  clipDuration = 5,
  clipOffsetX,
}: ComputeDropPositionParams): DropPosition => {
  const current = dataRef.current;
  const { editArea, grid } = getTimelineDomNodes(wrapper);
  const wrapperRect = wrapper.getBoundingClientRect();
  const editRect = (editArea ?? wrapper).getBoundingClientRect();
  const scrollLeft = grid?.scrollLeft ?? 0;
  const scrollTop = grid?.scrollTop ?? 0;
  const pixelsPerSecond = scaleWidth / scale;
  const effectiveOffsetX = clipOffsetX ?? (clipDuration * pixelsPerSecond) / 2;
  const leftInGrid = clientX - editRect.left + scrollLeft - effectiveOffsetX;
  const time = Math.max(0, (leftInGrid - startLeft) / pixelsPerSecond);

  const rowCount = current?.rows.length ?? 0;
  const rawRowIndex = rawRowIndexFromY(clientY, editRect.top, scrollTop, rowHeight);
  const isNewTrack = rowCount === 0 || rawRowIndex >= rowCount;
  const rowIndex = rowCount === 0
    ? 0
    : isNewTrack
      ? rowCount
      : Math.min(Math.max(rawRowIndex, 0), rowCount - 1);
  const visualRowIndex = rowCount > 0 ? Math.min(rowIndex, rowCount - 1) : -1;
  const targetRow = visualRowIndex >= 0 ? current?.rows[visualRowIndex] : undefined;
  const targetTrack = visualRowIndex >= 0 ? current?.tracks[visualRowIndex] : undefined;
  const rowTop = visualRowIndex >= 0
    ? editRect.top + visualRowIndex * rowHeight - scrollTop
    : editRect.top;
  const clipLeft = editRect.left + startLeft + time * pixelsPerSecond - scrollLeft;
  const clipWidth = Math.max(0, Math.min(clipDuration * pixelsPerSecond, editRect.right - clipLeft));
  const ghostCenter = clipLeft + clipWidth / 2;
  const trackKind = isNewTrack ? sourceKind : targetTrack?.kind ?? null;
  const isReject = !isNewTrack && sourceKind !== null && targetTrack?.kind !== undefined && sourceKind !== targetTrack.kind;

  return {
    time,
    rowIndex,
    trackId: isNewTrack ? undefined : targetRow?.id,
    trackKind,
    trackName: targetTrack?.label ?? targetTrack?.id ?? '',
    isNewTrack,
    isReject,
    screenCoords: {
      rowTop,
      rowLeft: wrapperRect.left,
      rowWidth: wrapperRect.width,
      rowHeight,
      clipLeft,
      clipWidth,
      ghostCenter,
    },
  };
};

export const inferDragKind = (event: ReactDragEvent<HTMLDivElement>): TrackKind | null => {
  const types = Array.from(event.dataTransfer.types);
  if (types.includes('asset-kind:audio')) return 'audio';
  if (types.includes('asset-kind:visual')) return 'visual';
  if (types.includes('asset-key')) return null;
  if (getDragType(event) === 'generation') return 'visual';
  if (event.dataTransfer.items.length > 0) {
    for (const item of Array.from(event.dataTransfer.items)) {
      if (item.type.startsWith('audio/')) {
        return 'audio';
      }
    }
    return 'visual';
  }
  return null;
};

import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
  type ReactNode,
  type RefObject,
  type UIEvent,
} from 'react';
import { TimeRuler } from '@/tools/video-editor/components/TimelineEditor/TimeRuler';
