.timeline-wrapper .timeline-editor {
  background: #09090b;
  color: #e4e4e7;
}

.timeline-wrapper .timeline-editor-header {
  background: #111114;
  border-bottom: 1px solid rgba(63, 63, 70, 0.8);
}

.timeline-wrapper .timeline-editor-edit-row {
  background: transparent;
}

.timeline-wrapper .timeline-editor-action {
  border: none;
  background: transparent;
}

.timeline-wrapper .timeline-editor-action:active {
  opacity: 0.72;
  z-index: 30;
}

/* Floating ghost clone shown during cross-track drag */
.cross-track-ghost {
  position: fixed;
  pointer-events: none;
  z-index: 99999;
  opacity: 0.8;
}

/* ── Drop indicator classes (shared by internal clip drag and external HTML5 drag-drop) ── */

.drop-indicator-row {
  position: fixed;
  background: rgb(137 180 250 / 0.08);
  border: 1px solid rgb(137 180 250 / 0.3);
  border-radius: 4px;
  pointer-events: none;
}

.drop-indicator-row--reject {
  background: rgb(250 137 137 / 0.12);
  border: 1px solid rgb(250 137 137 / 0.3);
}

.drop-indicator-line {
  position: fixed;
  width: 2px;
  background: #89b4fa;
  pointer-events: none;
  box-shadow: 0 0 6px rgba(137, 180, 250, 0.5);
}

.drop-indicator-ghost {
  position: fixed;
  background: rgba(137, 180, 250, 0.15);
  border: 1px dashed rgba(137, 180, 250, 0.4);
  border-radius: 4px;
  pointer-events: none;
  display: flex;
  align-items: center;
  justify-content: center;
}

.drop-indicator-ghost-label {
  font-size: 9px;
  font-weight: 600;
  color: rgba(137, 180, 250, 0.9);
}

.drop-indicator-label {
  position: fixed;
  background: rgba(137, 180, 250, 0.9);
  color: #1e1e2e;
  font-size: 9px;
  font-weight: 600;
  padding: 2px 6px;
  border-radius: 3px;
  pointer-events: none;
  white-space: nowrap;
}

/* External drag-over border glow */
.timeline-wrapper[data-drag-over='true'] {
  box-shadow: inset 0 0 0 1px rgba(56, 189, 248, 0.35);
}

/* "Drop to create matching track" affordance at bottom of edit area */
.timeline-wrapper .timeline-editor-edit-area.drop-target-new-track::after {
  content: 'Drop to create matching track';
  position: absolute;
  inset-inline: 16px;
  bottom: 8px;
  border: 1px dashed rgba(56, 189, 248, 0.4);
  background: rgba(8, 47, 73, 0.45);
  color: #bae6fd;
  text-align: center;
  padding: 6px 8px;
  border-radius: 8px;
  font-size: 11px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

